import { useState, useEffect, useRef } from "react";
import { useNavigate } from "react-router-dom"; // Essential for navigation

/* ─────────────────────────────────────────────
   FATEH EDUCATION — AI Voice Agent Landing Page
   Dark glassmorphism theme · React + Tailwind CSS
   ───────────────────────────────────────────── */

const css = {
  page: {
    background: "radial-gradient(ellipse 90% 55% at 50% -5%, #0d2547 0%, #060b14 50%, #030508 100%)",
    minHeight: "100vh",
    fontFamily: "'Space Grotesk', sans-serif",
    position: "relative",
    color: "#fff",
    overflowX: "hidden",
  },
  gridBg: {
    backgroundImage:
      "linear-gradient(rgba(37,99,235,0.07) 1px, transparent 1px), linear-gradient(90deg, rgba(37,99,235,0.07) 1px, transparent 1px)",
    backgroundSize: "48px 48px",
    position: "absolute",
    inset: 0,
    maskImage: "radial-gradient(ellipse 90% 65% at 50% 0%, black 20%, transparent 100%)",
    WebkitMaskImage: "radial-gradient(ellipse 90% 65% at 50% 0%, black 20%, transparent 100%)",
  },
  glassCard: {
    background: "linear-gradient(135deg, rgba(255,255,255,0.05) 0%, rgba(255,255,255,0.02) 100%)",
    backdropFilter: "blur(24px)",
    WebkitBackdropFilter: "blur(24px)",
    border: "1px solid rgba(255,255,255,0.09)",
    boxShadow: "0 8px 48px rgba(0,0,0,0.4), inset 0 1px 0 rgba(255,255,255,0.07)",
  },
  glassCardHoverStudent: {
    background: "linear-gradient(135deg, rgba(37,99,235,0.14) 0%, rgba(37,99,235,0.04) 100%)",
    border: "1px solid rgba(59,130,246,0.45)",
    boxShadow: "0 0 52px rgba(37,99,235,0.2), 0 12px 48px rgba(0,0,0,0.5), inset 0 1px 0 rgba(255,255,255,0.1)",
  },
  glassCardHoverCounsellor: {
    background: "linear-gradient(135deg, rgba(5,150,105,0.12) 0%, rgba(5,150,105,0.03) 100%)",
    border: "1px solid rgba(52,211,153,0.38)",
    boxShadow: "0 0 48px rgba(5,150,105,0.16), 0 12px 48px rgba(0,0,0,0.5), inset 0 1px 0 rgba(255,255,255,0.1)",
  },
  btnStudent: {
    background: "linear-gradient(135deg, #2563eb 0%, #1d4ed8 100%)",
    boxShadow: "0 0 24px rgba(37,99,235,0.5), 0 4px 16px rgba(0,0,0,0.3)",
  },
  btnCounsellor: {
    background: "linear-gradient(135deg, #059669 0%, #047857 100%)",
    boxShadow: "0 0 24px rgba(5,150,105,0.45), 0 4px 16px rgba(0,0,0,0.3)",
  },
  orb1: {
    position: "absolute", width: 500, height: 500, borderRadius: "50%",
    background: "radial-gradient(circle, rgba(37,99,235,0.15) 0%, transparent 70%)",
    top: -140, left: "8%", filter: "blur(50px)", pointerEvents: "none",
    animation: "orb1 12s ease-in-out infinite",
  },
  orb2: {
    position: "absolute", width: 380, height: 380, borderRadius: "50%",
    background: "radial-gradient(circle, rgba(5,150,105,0.12) 0%, transparent 70%)",
    top: 220, right: "5%", filter: "blur(50px)", pointerEvents: "none",
    animation: "orb2 10s ease-in-out infinite",
  },
};

// ── OFFICIAL FATEH LOGO REPLACEMENT ──
function FatehLogo({ size = 36 }) {
  // Calculated height based on input image ratio (W:H approx 1:1.15)
  const h = size * 1.15;
  return (
    <svg 
      width={size} 
      height={h} 
      viewBox="0 0 216 250" 
      fill="none" 
      xmlns="http://www.w3.org/2000/svg"
      style={{ display: 'block' }} // Fixes inline SVG alignment issues
    >
      {/* Blue Shield Background with the Inner Light Circle */}
      <path d="M108 0C68.6 0 35.8 17.1 14.5 44.1C5.2 55.7 0 69.8 0 84.7C0 148.6 44.8 214.2 108 243.6C171.2 214.2 216 148.6 216 84.7C216 69.8 210.8 55.7 201.5 44.1C180.2 17.1 147.4 0 108 0ZM108 22C138.8 22 166.1 36 182.7 57.5C190.2 67.2 194.4 79.1 194.4 92C194.4 146.1 156.4 201.7 108 226.7C59.6 201.7 21.6 146.1 21.6 92C21.6 79.1 25.8 67.2 33.3 57.5C49.9 36 77.2 22 108 22Z" fill="#0077D3"/>
      {/* Three Abstract Flame/Pen Marks */}
