// ── Animated counter ──
function Counter({ target, suffix = "" }) {
  const [val, setVal] = useState(0);
  const ref = useRef(null);
  useEffect(() => {
    const obs = new IntersectionObserver(([e]) => {
      if (e.isIntersecting) {
        let v = 0;
        const step = Math.ceil(target / 60);
        const t = setInterval(() => {
          v = Math.min(v + step, target);
          setVal(v);
          if (v >= target) clearInterval(t);
        }, 20);
      }
    }, { threshold: 0.4 });
    if (ref.current) obs.observe(ref.current);
    return () => obs.disconnect();
  }, [target]);
  return <span ref={ref}>{val.toLocaleString()}{suffix}</span>;
}

// ── Floating particles ──
function Particles() {
  const dots = Array.from({ length: 28 }, (_, i) => ({
    id: i, x: Math.random() * 100, y: Math.random() * 100,
    r: Math.random() * 1.5 + 0.5, delay: Math.random() * 5, dur: Math.random() * 6 + 6,
  }));
  return (
    <svg style={{ position: "absolute", inset: 0, width: "100%", height: "100%", pointerEvents: "none", opacity: 0.35 }}>
      {dots.map((d) => (
        <circle key={d.id} cx={`${d.x}%`} cy={`${d.y}%`} r={d.r} fill="#60a5fa">
          <animate attributeName="opacity" values="0.2;0.8;0.2" dur={`${d.dur}s`} begin={`${d.delay}s`} repeatCount="indefinite" />
        </circle>
      ))}
    </svg>
  );
}

// ── Typing headline ──
const LINES = ["Overseas Education.", "Your UK & Ireland Journey.", "AI-Powered Admissions."];
function TypingText() {
  const [line, setLine] = useState(0);
  const [txt, setTxt] = useState("");
  const [del, setDel] = useState(false);
  useEffect(() => {
    const target = LINES[line];
    if (!del && txt.length < target.length) {
      const t = setTimeout(() => setTxt(target.slice(0, txt.length + 1)), 60);
      return () => clearTimeout(t);
    }
    if (!del && txt.length === target.length) {
      const t = setTimeout(() => setDel(true), 2000);
      return () => clearTimeout(t);
    }
    if (del && txt.length > 0) {
      const t = setTimeout(() => setTxt(txt.slice(0, -1)), 32);
      return () => clearTimeout(t);
    }
    if (del && txt.length === 0) {
      setDel(false);
      setLine((l) => (l + 1) % LINES.length);
    }
  }, [txt, del, line]);
  return (
    <span style={{ color: "#60a5fa" }}>
      {txt}
      <span className="cursor-blink">|</span>
    }</span>
  );
}

